using System;

class Test
{
    static void Main()
    {
        // Simulate what the Linux file picker returns: a file URI with encoded spaces
        string fileUri = "file:///home/user/My%20Documents/test%20file.txt";
        string fileUriEncoded = "file:///home/user/My%20Documents/file%20with%20spaces.txt";

        Console.WriteLine("=== Testing with AbsolutePath (current code) ===");
        Console.WriteLine($"URI: {fileUri}");
        Console.WriteLine($"AbsolutePath: {new Uri(fileUri).AbsolutePath}");
        Console.WriteLine();

        Console.WriteLine("=== Testing with LocalPath (proposed fix) ===");
        Console.WriteLine($"URI: {fileUri}");
        Console.WriteLine($"LocalPath: {new Uri(fileUri).LocalPath}");
        Console.WriteLine();

        Console.WriteLine("=== More complex paths ===");
        Console.WriteLine($"URI: {fileUriEncoded}");
        Console.WriteLine($"AbsolutePath: {new Uri(fileUriEncoded).AbsolutePath}");
        Console.WriteLine($"LocalPath: {new Uri(fileUriEncoded).LocalPath}");

        // Verify the issue
        string absolutePath = new Uri(fileUri).AbsolutePath;
        string localPath = new Uri(fileUri).LocalPath;

        Console.WriteLine();
        Console.WriteLine($"AbsolutePath contains %20: {absolutePath.Contains("%20")}");
        Console.WriteLine($"LocalPath contains spaces: {localPath.Contains(" ")}");

        if (absolutePath.Contains("%20"))
        {
            Console.WriteLine("BUG REPRODUCED: AbsolutePath returns %20 instead of spaces!");
            Console.WriteLine($"  A file at '{absolutePath}' does not exist on the filesystem.");
        }

        if (!localPath.Contains("%20") && localPath.Contains(" "))
        {
            Console.WriteLine("FIX VERIFIED: LocalPath correctly returns spaces.");
            Console.WriteLine($"  A file at '{localPath}' exists on the filesystem.");
        }
    }
}
